# Let's extract panels from training example 0
# Grid is divided by color 1 borders
# Rows: 0,6,12,18 are border rows -> 3 row-blocks
# Cols: 0,6,12,18 are border cols -> 3 col-blocks
# Each panel interior is rows 1-5, 7-11, 13-17 x cols 1-5, 7-11, 13-17

inp = np.array(train_samples[0]['input'])
out = np.array(train_samples[0]['output'])

# Extract panels (including borders)
# Panel (r,c) spans rows r*6:r*6+7, cols c*6:c*6+7
panels = {}
for r in range(3):
    for c in range(3):
        panel = inp[r*6:r*6+7, c*6:c*6+7]
        panels[(r,c)] = panel

# Output panels
out_panels = {}
for r in range(3):
    out_panels[r] = out[r*6:r*6+7, :]

# For each row, find which panel differs
for r in range(3):
    row_panels = [panels[(r,c)].tolist() for c in range(3)]
    print(f"\nRow {r}:")
    for c in range(3):
        print(f"  Panel ({r},{c}): {row_panels[c]}")
    # Check which pairs are equal
    for i in range(3):
        for j in range(i+1,3):
            eq = np.array_equal(panels[(r,i)], panels[(r,j)])
            print(f"  ({r},{i}) == ({r},{j}): {eq}")
    print(f"  Output: {out_panels[r].tolist()}")

