tool_input.code:
# Training example 1: 19x25 -> 19x7
# 4 columns of panels, 3 rows
inp = np.array(train_samples[1]['input'])
out = np.array(train_samples[1]['output'])

# Panel size: 7x7 (including borders)
# Rows: 0,6,12,18 -> 3 row blocks
# Cols: 0,6,12,18,24 -> 4 col blocks

panels = {}
for r in range(3):
    for c in range(4):
        panel = inp[r*6:r*6+7, c*6:c*6+7]
        panels[(r,c)] = panel

out_panels = {}
for r in range(3):
    out_panels[r] = out[r*6:r*6+7, :]

for r in range(3):
    print(f"\nRow {r}:")
    # Find unique panel
    for i in range(4):
        for j in range(i+1,4):
            eq = np.array_equal(panels[(r,i)], panels[(r,j)])
            if not eq:
                print(f"  ({r},{i}) != ({r},{j})")

    # Which one is the odd one out?
    from collections import Counter
    panel_strs = [str(panels[(r,c)].tolist()) for c in range(4)]
    counts = Counter(panel_strs)
    for c in range(4):
        if counts[panel_strs[c]] == 1:
            print(f"  Unique: column {c}")
            print(f"  Match output: {np.array_equal(panels[(r,c)], out_panels[r])}")

